## Section1(not reported)
## Problem1(1.2.9.82)
## Author()
## Institution()
## Language(en-US)

DOCUMENT();

############################################################
# Load Macros
############################################################
loadMacros(
  "PGstandard.pl",
  "PGML.pl",
  "AnswerFormatHelp.pl",
  "PCCmacros.pl",
  "contextForm.pl",
  "contextInequalitySetBuilder.pl",
  "parserGraphTool.pl",
  "PGcourse.pl",
);
COMMENT('Authored in PreTeXt');

############################################################
# Header
############################################################
TEXT(beginproblem());

############################################################
# PG Setup Code
############################################################
$var = list_random('a'..'n','p'..'z','A'..'D', 'F'..'N','P'..'T','V'..'Z');
Context()->variables->are($var => 'Real');
Context()->noreduce('(-x)-y', '(-x)+y');
$sol = non_zero_random(-6, 6);
$m = list_random(-9..-2);
$b = non_zero_random(-9, 9);
$c = $m*$sol + $b;
$left = Formula("$m $var + $b")->reduce;
$right = Formula("$c")->reduce;
$sign = list_random('\lt', '\gt', '\leq', '\geq');
%interval = (
  '\gt'  => "(-inf, $sol)",
  '\lt'  => "($sol, inf)",
  '\geq' => "(-inf, $sol]",
  '\leq' => "[$sol, inf)"
);
Context("Interval");
$interval = Interval($interval{$sign});
InequalitySetBuilder::UseVerticalSuchThat();
Context("InequalitySetBuilder-Only");
Context()->variables->are($var => 'Real');
%perlsign = (
  '\gt'  => "<",
  '\lt'  => ">",
  '\geq' => "<=",
  '\leq' => ">="
);
$perlsign = $perlsign{$sign};
$setbuilder = Compute("{ $var | $var $perlsign $sol}");
$gt = GraphTool("{interval, $interval}")->with(
  availableTools => ['IntervalTool', 'IncludeExcludePointTool'],
  numberLine => 1,
  xAxisLabel => "$var",
  bBox => [ -8, 8 ],
  ticksDistanceX => 1,
  minorTicksX => 0,
  useBracketEnds => 1,
  showInStatic => 0,
  showCoordinateHints => 0,
);

############################################################
# Body
############################################################

BEGIN_PGML
Solve the inequality. Graph the solution set, and write the solution set using both interval notation and set-builder notation.

[`[$left][$sign][$right]`]

[_]{$gt}{1}

[@KeyboardInstructions('In interval notation. (If needed, type [|inf|]* or [|infinity|]* for [`\infty\text{.}`])')@]**

[_]{$interval}{12}

[@KeyboardInstructions('In set-builder notation. (If needed, type [|>=|]* for [`\geq\text{,}`] and [|<=|]* for [`\leq\text{.}`])')@]**

[_]{$setbuilder}{12}

END_PGML

############################################################
# End Problem
############################################################

ENDDOCUMENT();
